+                    }
+                    if tracker.record_rejection(index, reason) {
+                        tracker.mark_settled();
+                        let errors = tracker.collect_errors();
+                        resolution = Some(ResolutionData::RejectAny(tracker.result_promise, errors));
+                    }
+                }
+            }
+        }
